    sub     x9, sp, #MSG_SIZE
    str     wzr, [x9, #0]                     // m_source — kernel overwrites
    mov     w10, #VM_BRK
    str     w10, [x9, #4]                     // m_type = VM_BRK
    movz    x11, #0x0100, lsl #16
    movk    x11, #0x4000
    str     x11, [x9, #8]                     // payload[0..8] = new_break
    mov     x0, #ENDPOINT_VM
    mov     x1, #SENDREC
    mov     x2, x9
    svc     #0

    // --- touch heap page 0 (now in range): faults once, VM maps it ---
    movz    x20, #0x0100, lsl #16             // x20 = 0x0100_0000 (heap page 0)
    mov     x19, #0                           // persistent counter
    str     x19, [x20]

    // --- brk #2: grow heap to 0x0100_8000 ---
    sub     x9, sp, #MSG_SIZE
    str     wzr, [x9, #0]
    mov     w10, #VM_BRK
    str     w10, [x9, #4]
    movz    x11, #0x0100, lsl #16
    movk    x11, #0x8000
    str     x11, [x9, #8]                     // new_break = 0x0100_8000
    mov     x0, #ENDPOINT_VM
    mov     x1, #SENDREC
    mov     x2, x9
    svc     #0

    // --- touch heap page 1 (in range only after brk #2) ---
    movz    x21, #0x0100, lsl #16
    movk    x21, #0x4000                      // x21 = 0x0100_4000 (heap page 1)
    str     x19, [x21]

    // --- steady loop: write both pages, no further faults ---
1:
    str     x19, [x20]
    str     x19, [x21]
    add     x19, x19, #1
    b       1b
    .global _user_stub_d_end
_user_stub_d_end:
    .size _user_stub_d_start, _user_stub_d_end - _user_stub_d_start
```

**Message Construction on the EL0 Side:**

1. **Reserve**: `sub x9, sp, #MSG_SIZE` (104 bytes at `[SP_EL0-104, SP_EL0)`)
2. **m_source** (offset 0, 4 bytes): zeroed via `str wzr, [x9, #0]` — kernel overwrites with sender endpoint
3. **m_type** (offset 4, 4 bytes): `VM_BRK` (0xC01) via `mov w10, #VM_BRK; str w10, [x9, #4]`
4. **payload[0..8]** (offset 8, 8 bytes): new break address (u64) via `str x11, [x9, #8]` where x11 = `0x0100_4000` or `0x0100_8000`
5. **IPC trap**: `x0 = ENDPOINT_VM`, `x1 = SENDREC`, `x2 = &message`, `svc #0`

**Section Names & Stub Differences:**

- **Stub A** (`.rodata.user_stub_a`): ping-pong sender, increments counter x19 in SENDREC loop, peer=B
- **Stub B** (`.rodata.user_stub_b`): echo server, RECEIVE(ANY), SEND back with m_type mirrored
- **Stub C** (`.rodata.user_stub_c`): kernel-call client, SENDREC to SYSTEM with m_type=SYS_GETINFO, payload[0..4]=GET_WHOAMI
- **Stub D** (`.rodata.user_stub_d`): brk + page-fault demo, dual VM_BRK(0x0100_4000) → touch → VM_BRK(0x0100_8000) → touch → loop

