3	//! Per-process memory regions tracked by the VM server (slice 3.5).
4	//!
5	//! VM is the user-space authority on what virtual addresses a process may
6	//! touch. Before slice 3.5 it resolved *every* page fault by blindly mapping a
7	//! fresh page; now it consults a per-process region table so that only faults
8	//! inside a known region (today: the heap) are satisfied. Out-of-region faults
9	//! are a SIGSEGV (handled by the caller in `main.rs`).
10	//!
11	//! The table is a static `[ClientRegions; MAX_CLIENTS]` indexed by process
12	//! number. This mirrors the kernel's `PROC_TABLE` convention: an
13	//! `UnsafeCell<[T; N]>` inside a `#[repr(transparent)]` newtype with
14	//! `unsafe impl Sync`. The single-mutator invariant is even simpler here than
15	//! in the kernel — VM is a single EL0 thread with no interrupt handlers of its
16	//! own (IRQs trap into the kernel, never into VM), so the table is only ever
17	//! touched from VM's straight-line receive loop.
18	//!
19	//! `MAX_CLIENTS = 16` covers every boot process (proc numbers `0..=15`,
20	//! including stub D at `14`). Phase 4's `fork` will churn proc numbers past
21	//! this cap and revisit the keying; a 1024-slot table (`NR_PROCS`) would burn
22	//! ~512 KiB of BSS — 128 frames the ELF loader would map at boot — for no
23	//! benefit while only the boot stubs exist.
24	
25	use core::cell::UnsafeCell;
26	
27	use minixrs_kernel_shared::error::EINVAL;
28	
29	/// Fixed heap origin. Until PM supplies a real per-process memory layout
30	/// (Phase 4), VM and stub D agree on this VA by convention: `brk` grows the
31	/// heap as `[HEAP_BASE, new_break)` and stub D writes inside that range.
32	pub const HEAP_BASE: u64 = 0x0100_0000;
33	
34	/// aarch64 4 KiB page.
35	const PAGE_SIZE: u64 = 4096;
36	
37	/// Proc-number range the table can key. Boot procs are `0..=15`.
38	const MAX_CLIENTS: usize = 16;
39	
40	/// Regions tracked per process. One heap today; `mmap` regions (slice 3.6)
41	/// reuse the spare slots.
42	const MAX_REGIONS: usize = 4;
43	
44	/// What a region is for. `Unused` marks a free slot.
45	#[derive(Copy, Clone, PartialEq, Eq)]
46	pub enum Kind {
47	    Unused,
48	    Heap,
49	}
50	
51	/// A half-open virtual-address range `[start, end)` and what it backs.
52	#[derive(Copy, Clone)]
53	struct Region {
54	    start: u64,
55	    end: u64,
56	    kind: Kind,
57	}
58	
59	impl Region {
60	    const EMPTY: Self = Self {
61	        start: 0,
62	        end: 0,
63	        kind: Kind::Unused,
64	    };
65	
66	    fn contains(&self, addr: u64) -> bool {
67	        self.kind != Kind::Unused && addr >= self.start && addr < self.end
68	    }
69	}
70	
71	/// One process's region set.
72	#[derive(Copy, Clone)]
73	struct ClientRegions {
74	    regions: [Region; MAX_REGIONS],
75	}
76	
77	impl ClientRegions {
78	    const EMPTY: Self = Self {
79	        regions: [Region::EMPTY; MAX_REGIONS],
80	    };
81	
82	    /// True if `addr` falls inside one of this client's regions.
83	    fn contains(&self, addr: u64) -> bool {
84	        self.regions.iter().any(|r| r.contains(addr))
85	    }
86	
87	    /// Set the program break to `new_break`, growing or creating the heap
88	    /// region as `[HEAP_BASE, page_align_up(new_break))`. Returns the resulting
89	    /// break, or `EINVAL` if `new_break` is below `HEAP_BASE`, the page-aligned
90	    /// break would overflow `u64`, or no region slot is free for a new heap.
91	    fn set_brk(&mut self, new_break: u64) -> Result<u64, i32> {
92	        if new_break < HEAP_BASE {
93	            return Err(EINVAL);
94	        }
95	        // page_align_up, guarding the round-up add against wraparound near
96	        // `u64::MAX` (a silent wrap would yield a tiny `end` in `--release`).
97	        let end = new_break
98	            .checked_add(PAGE_SIZE - 1)
99	            .map(|v| v & !(PAGE_SIZE - 1))
100	            .ok_or(EINVAL)?;
101	
102	        // Grow the existing heap region if present.
103	        for r in self.regions.iter_mut() {
104	            if r.kind == Kind::Heap {
105	                r.end = end;
106	                return Ok(end);
107	            }
108	        }
109	        // Otherwise claim a free slot for a fresh heap region.
110	        for r in self.regions.iter_mut() {
111	            if r.kind == Kind::Unused {
112	                *r = Region {
113	                    start: HEAP_BASE,
114	                    end,
115	                    kind: Kind::Heap,
116	                };
117	                return Ok(end);
118	            }
119	        }
120	        Err(EINVAL)
121	    }
122	}
