124	/// `UnsafeCell`-wrapped static table. See the module-level note for the
125	/// single-mutator invariant that makes the `Sync` impl sound.
126	#[repr(transparent)]
127	struct RegionTable(UnsafeCell<[ClientRegions; MAX_CLIENTS]>);
128	
129	// SAFETY: VM is a single-threaded EL0 process with no interrupt handlers of
130	// its own; the table is only ever accessed from VM's straight-line receive
131	// loop, so there is never concurrent access.
132	unsafe impl Sync for RegionTable {}
133	
134	static TABLE: RegionTable = RegionTable(UnsafeCell::new([ClientRegions::EMPTY; MAX_CLIENTS]));
135	
136	/// In-range proc number → table index, or `None` if `nr` is a kernel task
137	/// (negative) or past the boot cap.
138	fn client_idx(nr: i32) -> Option<usize> {
139	    let idx = usize::try_from(nr).ok()?;
140	    (idx < MAX_CLIENTS).then_some(idx)
141	}
142	
143	/// Borrow the client's region set immutably (read path).
144	fn client_ref(nr: i32) -> Option<&'static ClientRegions> {
145	    let idx = client_idx(nr)?;
146	    // SAFETY: single-mutator invariant (module note); shared read, `idx` in
147	    // range. No `&mut` to the table is live during VM's straight-line loop.
148	    let table = unsafe { &*TABLE.0.get() };
149	    Some(&table[idx])
150	}
151	
152	/// Borrow the client's region set mutably (write path).
153	fn client_mut(nr: i32) -> Option<&'static mut ClientRegions> {
154	    let idx = client_idx(nr)?;
155	    // SAFETY: single-mutator invariant (module note); `idx < MAX_CLIENTS`.
156	    let table = unsafe { &mut *TABLE.0.get() };
157	    Some(&mut table[idx])
158	}
159	
160	/// True if `addr` falls inside one of `nr`'s regions. The VM fault path only
161	/// satisfies faults for which this returns true.
162	pub fn contains(nr: i32, addr: u64) -> bool {
163	    client_ref(nr).is_some_and(|client| client.contains(addr))
164	}
165	
166	/// Set process `nr`'s program break to `new_break`, growing or creating its
167	/// heap region as `[HEAP_BASE, page_align_up(new_break))`. Returns the
168	/// resulting break on success, or `EINVAL` if `nr` is untrackable or
169	/// `new_break` is below `HEAP_BASE`.
170	///
171	/// No frames are mapped here — pages fault in lazily on first touch and are
172	/// resolved through [`contains`] in the fault path.
173	pub fn set_brk(nr: i32, new_break: u64) -> Result<u64, i32> {
174	    client_mut(nr).ok_or(EINVAL)?.set_brk(new_break)
175	}
