1	// SPDX-License-Identifier: BSD-3-Clause
2	// Copyright (c) 2025-2026 Kevin Barnard and minix.rs Contributors
3	//! minix.rs VM (virtual memory) server.
4	//!
5	//! The first *real* user-space process (introduced in slice 3.4a as a build
6	//! milestone). Built as a freestanding aarch64 ELF (see `servers/vm/user.ld`),
7	//! embedded into the kernel image by `kernel/build.rs`, and loaded into its
8	//! own per-process AddrSpace at boot by `arch::aarch64::userland::vm_bootstrap`.
9	//!
10	//! Slice 3.4b made it functional: a `RECEIVE(ANY)` loop that resolves page
11	//! faults. When an EL0 process faults on an unmapped page, the kernel records
12	//! the fault, blocks the faulter on `RTS_PAGEFAULT`, and sends VM a
13	//! `VM_PAGEFAULT` message (`m_source` = faulter, payload = fault addr/flags).
14	//! VM maps a fresh page into the faulter via `SYS_VMCTL(VMCTL_PT_MAP)` and
15	//! unblocks it via `SYS_VMCTL(VMCTL_CLEAR_PAGEFAULT)`. No `alloc` crate — the
16	//! kernel owns the frame allocator; VM only drives policy.
17	//!
18	//! Slice 3.5 adds memory to VM: a per-process [`region`] table and a `VM_BRK`
19	//! request that grows a process's heap region. Page faults are now satisfied
20	//! only when the address lies inside a known region; out-of-region faults take
21	//! a SIGSEGV path (logged, faulter left blocked — real signals are Phase 4).
22	//! `VM_MMAP` arrives in slice 3.6.
23	
24	// Freestanding for the real (bare-metal) build, but a normal host binary under
25	// `cargo test` so `region`'s logic gets host-runnable unit tests. The test
26	// harness needs `std` and its own entry point, so `no_std`/`no_main` and the
27	// `_start` shim below are all gated to `not(test)`.
28	#![cfg_attr(not(test), no_std)]
29	#![cfg_attr(not(test), no_main)]
30	
31	mod region;
32	
33	use minixrs_ipc::{ipc_receive, ipc_send, ipc_sendrec};
34	use minixrs_kernel_shared::Message;
35	use minixrs_kernel_shared::callnr::{
36	    SYS_VMCTL, VM_BRK, VM_PAGEFAULT, VMCTL_CLEAR_PAGEFAULT, VMCTL_PROT_WRITE, VMCTL_PT_MAP,
37	};
38	use minixrs_kernel_shared::com::{SYSTEM, boot_endpoint};
39	use minixrs_kernel_shared::endpoint::{ANY, Endpoint, endpoint_proc};
40	use minixrs_kernel_shared::error::OK;
41	
42	/// aarch64 4 KiB page size — VM only needs to page-align fault addresses.
43	const PAGE_SIZE: u64 = 4096;
44	
45	/// ELF entry point. The kernel primes `SP_EL0` before `eret`, so `_start`
46	/// can dive straight into Rust without setting up a stack itself.
47	// Gate the whole shim to `not(test)`: under `cargo test` the crate links as a
48	// normal host executable, and an exported `_start` would collide with the C
49	// runtime's `_start` (a hard "duplicate symbol" error on the GNU/Linux linker).
50	#[cfg(not(test))]
51	#[unsafe(no_mangle)]
52	// `.text._start` is an ELF section name; gate it to the bare-metal target so
53	// `cargo check --workspace` on a Mach-O host (which rejects the specifier)
54	// still type-checks this crate. `ENTRY(_start)` in user.ld roots the symbol
55	// either way, so ordering it first in `.text` is a nicety, not a requirement.
56	#[cfg_attr(target_os = "none", unsafe(link_section = ".text._start"))]
57	pub extern "C" fn _start() -> ! {
58	    main()
59	}
60	
61	// Only `_start` calls `main`; under `cargo test` `_start` is gone, so `main`
62	// (and the message helpers it alone reaches) would read as dead code.
63	#[cfg_attr(test, allow(dead_code))]
64	fn main() -> ! {
65	    let system = boot_endpoint(SYSTEM);
66	    let mut msg = Message {
67	        m_source: 0,
68	        m_type: 0,
69	        payload: [0u8; 96],
70	    };
71	    loop {
72	        if ipc_receive(ANY, &mut msg) != 0 {
73	            continue;
74	        }
75	        match msg.m_type {
76	            VM_PAGEFAULT => handle_pagefault(system, msg.m_source, rd_u64(&msg, 0)),
77	            VM_BRK => handle_brk(&mut msg),
78	            // Unknown request: drop it. VM_MMAP arrives in slice 3.6.
79	            _ => {}
80	        }
81	    }
82	}
83	
84	/// Resolve a page fault for `faulting_e` at `far`.
85	///
86	/// Slice 3.5 gates this on the faulter's [`region`] table: only faults inside a
87	/// known region (today, the heap) are satisfied. A fault outside every region
88	/// is a SIGSEGV — VM returns without mapping or clearing, leaving the faulter
89	/// blocked on `RTS_PAGEFAULT` (the only "kill" available until PM + signals in
90	/// Phase 4). VM cannot print from EL0, so this path is silent; the symptom is a
91	/// process that stops making progress.
92	fn handle_pagefault(system: Endpoint, faulting_e: Endpoint, far: u64) {
93	    let nr = endpoint_proc(faulting_e).get();
94	    if !region::contains(nr, far) {
95	        // SIGSEGV: unmapped access outside any region. Leave it blocked.
96	        return;
97	    }
98	
99	    let page = far & !(PAGE_SIZE - 1);
100	
101	    // SYS_VMCTL(VMCTL_PT_MAP, target=faulting_e, vaddr=page, prot=WRITE).
102	    // The kernel allocates + maps the frame; we ignore the returned PA — the
103	    // region table records the VA range, and the kernel owns the frames.
104	    let mut m = Message {
105	        m_source: 0,
106	        m_type: SYS_VMCTL,
107	        payload: [0u8; 96],
108	    };
109	    wr_i32(&mut m, 0, VMCTL_PT_MAP);
110	    wr_i32(&mut m, 4, faulting_e);
111	    wr_u64(&mut m, 8, page);
112	    wr_i32(&mut m, 16, VMCTL_PROT_WRITE);
113	    let _ = ipc_sendrec(system, &mut m);
114	
115	    // SYS_VMCTL(VMCTL_CLEAR_PAGEFAULT, target=faulting_e) — unblock the faulter.
116	    let mut m = Message {
117	        m_source: 0,
118	        m_type: SYS_VMCTL,
119	        payload: [0u8; 96],
120	    };
121	    wr_i32(&mut m, 0, VMCTL_CLEAR_PAGEFAULT);
122	    wr_i32(&mut m, 4, faulting_e);
123	    let _ = ipc_sendrec(system, &mut m);
124	}
125	
126	/// Handle a `VM_BRK` request: set the caller's program break, growing or
127	/// creating its heap region. No frames are mapped here — pages fault in lazily
128	/// and are then satisfied by [`handle_pagefault`] via the region check. Reply
129	/// to the caller (it issued a SENDREC) with `m_type = OK` and the resulting
130	/// break in payload `0..8`, or the negative error in `m_type`.
131	fn handle_brk(msg: &mut Message) {
132	    let caller_e = msg.m_source;
133	    let nr = endpoint_proc(caller_e).get();
134	    let new_break = rd_u64(msg, 0);
135	
136	    let reply_type = match region::set_brk(nr, new_break) {
137	        Ok(brk) => {
138	            wr_u64(msg, 0, brk);
139	            OK
140	        }
141	        Err(e) => e,
142	    };
143	
144	    msg.m_type = reply_type;
145	    msg.m_source = 0; // kernel overwrites on delivery
146	    let _ = ipc_send(caller_e, msg);
147	}
148	
149	// Native-endian payload accessors, mirroring the kernel's `do_vmctl` reads.
150	fn rd_u64(m: &Message, off: usize) -> u64 {
151	    let mut b = [0u8; 8];
152	    b.copy_from_slice(&m.payload[off..off + 8]);
153	    u64::from_ne_bytes(b)
154	}
155	
156	fn wr_i32(m: &mut Message, off: usize, v: i32) {
157	    m.payload[off..off + 4].copy_from_slice(&v.to_ne_bytes());
158	}
159	
160	fn wr_u64(m: &mut Message, off: usize, v: u64) {
161	    m.payload[off..off + 8].copy_from_slice(&v.to_ne_bytes());
162	}
163	
164	// The freestanding panic handler; under `cargo test` std supplies its own.
165	#[cfg(not(test))]
166	#[panic_handler]
167	fn panic(_: &core::panic::PanicInfo) -> ! {
168	    loop {}
169	}
170

