1	// SPDX-License-Identifier: BSD-3-Clause
2	// Copyright (c) 2025-2026 Kevin Barnard and minix.rs Contributors
3	//! `SYS_VMCTL` — kernel-mediated page-table control.
4	//!
5	//! minix.rs keeps every unsafe PTE write and the physical frame allocator in
6	//! the kernel; the user-space VM server (slice 3.4) drives paging *policy* by
7	//! issuing the subcalls implemented here. This mirrors MINIX 3's split of
8	//! mechanism (kernel) from policy (VM) while moving frame ownership kernel-side
9	//! (MINIX 3's VM owns physical memory directly).
10	//!
11	//! Each subcall names a *target* process by endpoint — slice 3.3 only ever
12	//! sees a process targeting itself (stub D pre-maps then frees its own heap),
13	//! but the cross-process shape is what 3.4's VM needs when it resolves another
14	//! process's fault. Resolution mirrors `ipc/send.rs`: `endpoint_proc` →
15	//! `proc_index`, with the `SELF` sentinel mapped to the caller.
16	//!
17	//! ## Trust model
18	//!
19	//! There is no *per-target* authorization here: any caller that reaches this
20	//! handler may name any process (a kernel task slot — negative `ProcNr` —
21	//! included) and mutate its page tables, fault state, and run-queue status.
22	//! The single gate is `Priv::k_call_mask` granting `SYS_VMCTL`, checked in
23	//! `kernel_call_dispatch` before we run. This is the deliberate MINIX 3
24	//! mechanism/policy split: `SYS_VMCTL` is privileged and the VM server (3.4)
25	//! is its sole intended holder — VM is trusted to target only processes it
26	//! legitimately manages, exactly as MINIX 3 trusts its VM. If a future slice
27	//! hands `SYS_VMCTL` to a less-trusted process, target authorization must be
28	//! added before that lands.
29	//!
30	//! ## Message payload layout (offsets within `Message::payload`)
31	//!
32	//! | offset  | field            | direction | subcalls                     |
33	//! |---------|------------------|-----------|------------------------------|
34	//! |  0..4   | subcall selector | in        | all                          |
35	//! |  4..8   | target endpoint  | in        | all (`SELF` = caller)        |
36	//! |  8..16  | `vaddr` (u64)    | in        | `PT_MAP`, `PT_UNMAP`         |
37	//! | 16..20  | prot bits (i32)  | in        | `PT_MAP`                     |
38	//! | 16..24  | `pa` (u64)       | out       | `PT_MAP` (allocated frame)   |
39	//! |  8..16  | fault addr (u64) | out       | `GET_PAGEFAULT`              |
40	//! | 16..20  | fault flags(u32) | out       | `GET_PAGEFAULT`              |
41	//! | 20..28  | fault ip (u64)   | out       | `GET_PAGEFAULT`              |
42	//!
43	//! Run-queue transitions (`CLEAR_PAGEFAULT`, `VMINHIBIT_*`) use the
44	//! `sched::rts_set`/`rts_unset` capture-then-borrow-end pattern that
45	//! `ipc::send::mini_send` established, so the `&mut Proc` borrow ends before
46	//! the internal `enqueue`/`dequeue` re-borrows the same slot.
47	
48	use core::fmt::Write;
49	use core::sync::atomic::{AtomicU64, Ordering};
50	
51	use minixrs_kernel_shared::ProcNr;
52	use minixrs_kernel_shared::callnr::{
53	    NR_VMCTL_SUBCALLS, VMCTL_CLEAR_PAGEFAULT, VMCTL_GET_PAGEFAULT, VMCTL_PROT_EXEC,
54	    VMCTL_PROT_WRITE, VMCTL_PT_MAP, VMCTL_PT_UNMAP, VMCTL_VMINHIBIT_CLEAR, VMCTL_VMINHIBIT_SET,
55	};
56	use minixrs_kernel_shared::endpoint::{Endpoint, SELF, endpoint_proc};
57	use minixrs_kernel_shared::error::{EINVAL, ENOMEM, OK};
58	use minixrs_kernel_shared::message::Message;
59	
60	use crate::arch::aarch64::addrspace::{MapError, Prot, map_page_in, unmap_page_in};
61	use crate::arch::aarch64::mmu;
62	use crate::mm::{Frame, alloc_frame, free_frame};
63	use crate::proc::flags::{RTS_PAGEFAULT, RTS_VMINHIBIT};
64	use crate::proc::table::{N_PROC_SLOTS, proc_index};
65	use crate::proc::{PageFaultState, Proc, sched};
66	use crate::uart::Uart;
67	
68	/// How many `PT_MAP`/`PT_UNMAP` calls get a detailed head trace before steady
69	/// state falls back to the `[ksys N]` sampling in `kernel_call_sendrec`.
70	/// Stub D loops at kernel-call speed, so an unsampled per-call trace would
71	/// drown everything else (same reasoning as slice 2.6's `TRACE_HEAD`).
72	const VMCTL_TRACE_HEAD: u64 = 6;
73	static MAP_COUNT: AtomicU64 = AtomicU64::new(0);
74	static UNMAP_COUNT: AtomicU64 = AtomicU64::new(0);
75	
76	/// `SYS_VMCTL` entry point. Dispatches by subcall selector after resolving the
77	/// target process named in the payload.
78	pub(super) fn do_vmctl(
79	    proc_table: &mut [Proc; N_PROC_SLOTS],
80	    caller_nr: ProcNr,
81	    msg: &mut Message,
82	) -> i32 {
83	    let subcall = read_i32(msg, 0);
84	    let target_e: Endpoint = read_i32(msg, 4);
85	    // No per-target authorization — the caller is trusted via `k_call_mask`
86	    // (see the "Trust model" note above). `target_nr` may be any slot,
87	    // including a kernel task; `proc_index` only range-checks it.
88	    let target_nr = if target_e == SELF {
89	        caller_nr
90	    } else {
91	        endpoint_proc(target_e)
92	    };
93	    let Some(target_idx) = proc_index(target_nr) else {
94	        return EINVAL;
95	    };
96	
97	    // Lock subcall coverage: adding a `VMCTL_*` without a match arm is a
98	    // compile error.
99	    const _: () = assert!(
100	        NR_VMCTL_SUBCALLS == 6,
101	        "expand do_vmctl when a new VMCTL_* subcall lands",
102	    );
103	    match subcall {
104	        VMCTL_PT_MAP => pt_map(proc_table, target_idx, msg),
105	        VMCTL_PT_UNMAP => pt_unmap(proc_table, target_idx, msg),
106	        VMCTL_CLEAR_PAGEFAULT => clear_pagefault(proc_table, target_idx),
107	        VMCTL_GET_PAGEFAULT => get_pagefault(proc_table, target_idx, msg),
108	        VMCTL_VMINHIBIT_SET => set_vminhibit(proc_table, target_idx, true),
109	        VMCTL_VMINHIBIT_CLEAR => set_vminhibit(proc_table, target_idx, false),
110	        _ => EINVAL,
111	    }
112	}
113	
114	/// `VMCTL_PT_MAP` — allocate a fresh frame and map it into the target's AS.
115	///
116	/// The kernel allocates because it owns the frame allocator; the reply carries
117	/// the chosen PA so VM (3.4) can track the frame for later `PT_UNMAP`.
118	fn pt_map(proc_table: &mut [Proc; N_PROC_SLOTS], target_idx: usize, msg: &mut Message) -> i32 {
119	    let vaddr = read_u64(msg, 8);
120	    let prot_bits = read_i32(msg, 16);
121	    let prot = Prot {
122	        writable: prot_bits & VMCTL_PROT_WRITE != 0,
123	        executable: prot_bits & VMCTL_PROT_EXEC != 0,
124	    };
125	
126	    // Snapshot the target's AS coordinates, then drop the borrow before
127	    // touching the frame allocator / page tables (neither aliases the proc
128	    // table).
129	    let (ttbr0_pa, asid, name) = {
130	        let p = &proc_table[target_idx];
131	        (p.ttbr0_pa, p.asid, p.name[0])
132	    };
133	    if ttbr0_pa == 0 {
134	        return EINVAL; // target never runs at EL0 (kernel task / unset slot)
135	    }
136	
137	    let frame = match alloc_frame() {
138	        Some(f) => f,
139	        None => return ENOMEM,
140	    };
141	    match map_page_in(ttbr0_pa, vaddr, frame.addr(), prot) {
142	        Ok(()) => {}
143	        // Already-mapped or misaligned/out-of-range: hand the frame back and
144	        // report the error rather than leaking it.
145	        Err(MapError::AlreadyMapped) | Err(_) => {
146	            free_frame(frame);
147	            return EINVAL;
148	        }
149	    }
150	    // SAFETY: ASID-tagged TLBI. The target's TTBR0 may or may not be the live
151	    // one; ASID-tagged invalidation covers that ASID's entries either way.
152	    unsafe { mmu::flush_tlb_asid(asid) };
153	
154	    // Reply: the allocated PA (overwrites the prot-bits input word).
155	    write_u64(msg, 16, frame.addr());
156	
157	    let n = MAP_COUNT.fetch_add(1, Ordering::Relaxed) + 1;
158	    if n <= VMCTL_TRACE_HEAD {
159	        let mut uart = Uart::new();
160	        let _ = writeln!(
161	            uart,
162	            "[ksys VMCTL_PT_MAP] proc={} va={vaddr:#x} pa={:#x} result=0",
163	            name as char,
164	            frame.addr(),
165	        );
166	    }
167	    OK
168	}
169	
170	/// `VMCTL_PT_UNMAP` — clear the PTE at `vaddr` and free its backing frame.
171	///
172	/// Assumes the leaf is an anonymous, kernel-allocated frame (everything
173	/// `PT_MAP` installs is). Mapping a caller-supplied device/shared PA — which
174	/// must *not* be freed here — is a future subcall.
175	fn pt_unmap(proc_table: &mut [Proc; N_PROC_SLOTS], target_idx: usize, msg: &mut Message) -> i32 {
176	    let vaddr = read_u64(msg, 8);
177	    let (ttbr0_pa, asid, name) = {
178	        let p = &proc_table[target_idx];
179	        (p.ttbr0_pa, p.asid, p.name[0])
180	    };
181	    if ttbr0_pa == 0 {
182	        return EINVAL;
183	    }
184	
185	    let Some(pa) = unmap_page_in(ttbr0_pa, vaddr) else {
186	        return EINVAL; // nothing mapped at vaddr
187	    };
188	    free_frame(Frame::from_addr(pa));
189	    // SAFETY: ASID-tagged TLBI; same rationale as `pt_map`.
190	    unsafe { mmu::flush_tlb_asid(asid) };
191	
192	    let n = UNMAP_COUNT.fetch_add(1, Ordering::Relaxed) + 1;
193	    if n <= VMCTL_TRACE_HEAD {
194	        let mut uart = Uart::new();
195	        let _ = writeln!(
196	            uart,
197	            "[ksys VMCTL_PT_UNMAP] proc={} va={vaddr:#x} pa={pa:#x} result=0",
198	            name as char,
199	        );
200	    }
201	    OK
202	}
