/// process; the payload carries the fault address (`0..8`, u64) and fault
/// flags (`8..12`, u32). VM resolves it via `SYS_VMCTL(VMCTL_PT_MAP)` +
/// `SYS_VMCTL(VMCTL_CLEAR_PAGEFAULT)`.
pub const VM_PAGEFAULT: i32 = VM_RQ_BASE;

