            VMCTL_PT_UNMAP,
            VMCTL_CLEAR_PAGEFAULT,
            VMCTL_GET_PAGEFAULT,
            VMCTL_VMINHIBIT_SET,
            VMCTL_VMINHIBIT_CLEAR,
