    fn mmap_bumps_address_each_call() {
        let mut c = ClientRegions::EMPTY;
        let a = c.mmap(0x2000).unwrap();
        let b = c.mmap(0x1000).unwrap();
        assert_eq!(b, a + 0x2000);
        assert!(c.contains(a));
        assert!(c.contains(b));
    }

